#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int last = N % 10;
        int first = N;
        while (first >= 10) {
            first /= 10;
        }
        printf("%d\n", first + last);
    }
    return 0;
}

